function getLogoHTML(themeName) {
    const logos = {
        dark: 'ECOTRACK',
        japan: 'エコトラック',
        germany: 'ECOTRACK',
        scandinavia: 'ECOTRACK',
        tropical: '🌴 ECOTRACK 🌴',
        nordic: '◆ ECOTRACK ◆'
    };
    return logos[themeName] || 'ECOTRACK';
}
